#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return flag ? -res : res ;
}
const int N=20,Mod=998244353;
int dp[1<<N|15][2],g[1<<N|15],n,a[N+10],Sm[1<<N|15],ans;
inline void DN(int &x){x>=Mod?x-=Mod:0;} 
int main()
{
	n=read();for(int i=0;i<n;++i)Sm[1<<i]=read();
	for(int S=1;S<(1<<n);++S)if(S^(S&-S))DN(Sm[S]=Sm[S^(S&-S)]+Sm[S&-S]);
	for(int i=0;i<n;++i)dp[1<<i][Sm[1<<i]>=0]=1,g[1<<i]=Sm[1<<i]<0;int len=(1<<n)-1;
	g[0]=1;for(int S=1;S<(1<<n);++S)
	{
		for(int i=0;i<n;++i)if(!((S>>i)&1))
		{
			int T=S|(1<<i);if(g[S]&&Sm[T]<0)DN(g[T]+=g[S]);
			if(Sm[T]>=0)DN(dp[T][1]+=dp[S][1]);else DN(dp[T][0]+=dp[S][1]);
		}
		
	}
	for(int S=1;S<=len;++S){DN(Sm[S]+=Mod);ans=(ans+1ll*Sm[S]*(dp[S][0]+dp[S][1])%Mod*g[len^S])%Mod;}
	printf("%d\n",ans);return 0;
}
